// ---- helpers --------------------------------------------------------------

func tabClass(active, want string) string {
	if active == want {
		return "btn"
	}
	return "btn ghost"
}

func guestNameOrFallback(name string) string {
	if name == "" {
		return "Unnamed guest"
	}
	return name
}

func lobbyMsgSide(kind string) string {
	if kind == "host" {
		return "own"
	}
	return "other"
}

func promoteResultClass(errMsg string) string {
	if errMsg != "" {
		return "error"
	}
	return "success"
}

